import React from 'react';
import MarkdownEditor from '../Editor/MarkdownEditor';
import MarkdownPreview from '../Editor/MarkdownPreview';
import { useNotes } from '../../context/NotesContext';
import ExportButton from '../UI/ExportButton';
import { useScrollSync } from '../../hooks/useScrollSync';

const SplitLayout = () => {
  const { currentNote, loading, updateCurrentNoteLocally } = useNotes();
  const { editorRef, previewRef } = useScrollSync();

  const handleTitleChange = (title) => {
    updateCurrentNoteLocally({ title });
  };

  const handleContentChange = (content) => {
    updateCurrentNoteLocally({ content });
  };

  if (loading) {
    return (
      <div className="main-content">
        <div className="loading">
          <div className="loading-spinner"></div>
          <span>Loading note...</span>
        </div>
      </div>
    );
  }

  if (!currentNote) {
    return (
      <div className="main-content">
        <div className="empty-state">
          <div className="empty-state-icon">ð“</div>
          <div className="empty-state-title">Select a note</div>
          <div className="empty-state-text">
            Choose a note from the sidebar or create a new one
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="main-content">
      <div className="editor-layout">
        <div className="editor-panel">
          <div className="panel-header">
            Editor
            <div style={{ marginLeft: 'auto' }}>
              <ExportButton note={currentNote} />
            </div>
          </div>
          <div style={{ padding: '20px', borderBottom: '1px solid var(--border-color)' }}>
            <input
              type="text"
              value={currentNote.title || ''}
              onChange={(e) => handleTitleChange(e.target.value)}
              placeholder="Note title..."
              style={{
                width: '100%',
                padding: '12px',
                border: '1px solid var(--border-color)',
                borderRadius: '4px',
                fontSize: '16px',
                fontWeight: '600',
                outline: 'none'
              }}
            />
          </div>
          <MarkdownEditor
            value={currentNote.content || ''}
            onChange={handleContentChange}
            placeholder="Start writing in Markdown..."
          />
        </div>
        <div className="preview-panel">
          <div className="panel-header">Preview</div>
          <MarkdownPreview content={currentNote.content} />
        </div>
      </div>
    </div>
  );
};

export default SplitLayout;
